const ctx=$json.ctx;
const rules='You are the early-warning radar for Tecknuovo, a UK digital-delivery consultancy. Below are EXCERPTS of this week\'s client-call transcripts, account by account, plus the risks ALREADY formally flagged per account. Your ONLY job: find EMERGING concerns NOT in already_flagged - things a sharp managing director would want on her radar BEFORE they become formal risks. Look for: hesitation or friction around budgets, renewals or contracts; client-side reorganisations, departures or new decision-makers; repeated small frustrations; cooling tone or shrinking engagement; dependencies outside our control. Judge from Tecknuovo\'s perspective. RULES: maximum 5 items ACROSS ALL accounts (up to 2 per account), each ONE sentence naming the account and why it deserves watching, each with a SHORT verbatim quote from the transcript as evidence (copy exactly, max 25 words). Do NOT repeat anything in already_flagged. If nothing genuine is emerging return {"items":[]} - never invent. Never use em dashes. Return ONLY JSON: {"items":[{"account":"...","insight":"...","quote":"..."}]}';
const prompt=rules+'\n\nTHE WEEK\'S DATA:\n'+JSON.stringify(ctx);
return [{json:{prompt}}];

function parseModelJson(t){
  const m=String(t||'').match(/\{[\s\S]*\}/); if(!m){return null;}
  let s=m[0];
  try{return JSON.parse(s);}catch(e){}
  let out='',inStr=false,esc=false;
  for(const ch of s){
    if(esc){out+=ch;esc=false;continue;}
    if(ch==='\\'){out+=ch;esc=true;continue;}
    if(ch==='"'){inStr=!inStr;out+=ch;continue;}
    if(inStr&&ch==='\n'){out+='\\n';continue;}
    if(inStr&&ch==='\r'){continue;}
    if(inStr&&ch==='\t'){out+='\\t';continue;}
    out+=ch;
  }
  try{return JSON.parse(out);}catch(e){return null;}
}
const merged=[];
for(const it of $input.all()){
  const raw=(it.json.text||it.json.response||it.json.output||'').toString().trim();
  const obj=parseModelJson(raw); if(!obj) continue;
  const items=Array.isArray(obj.items)?obj.items:[];
  for(const x of items.slice(0,2)){
    const row={account:String((x&&x.account)||'').slice(0,120),insight:String((x&&x.insight)||'').slice(0,300),quote:String((x&&x.quote)||'').slice(0,220)};
    if(row.insight){merged.push(row);}
  }
}
const items=merged.slice(0,8);
const e=function(s){return String(s).replace(/'/g,"''")};
const sql="INSERT INTO briefs (audience,period_start,period_end,content) VALUES ('radar', now()::date-7, now()::date, '"+e(JSON.stringify({items:items}))+"'::jsonb);";
return [{json:{sql,found:items.length}}];
